package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;

import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;

public class Main {
    public static void main(String[] args) throws Exception {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-file>");
            System.exit(1);
        }

        Path sourceFile = Paths.get(args[0]);
        transformSource(sourceFile);
    }

    public static void transformSource(Path sourceFile) throws Exception {
        CompilationUnit cu = StaticJavaParser.parse(sourceFile);

        List<ImportDeclaration> imports = cu.getImports();
        for (ImportDeclaration importDecl : imports) {
            String name = importDecl.getNameAsString();
            if (name.startsWith("javax.servlet")) {
                String newName = name.replace("javax.servlet", "jakarta.servlet");
                importDecl.setName(newName);
            }
        }

        String transformedCode = cu.toString();
        Files.writeString(sourceFile, transformedCode);

        System.out.println("Transformed: " + sourceFile);
    }
}

